import React from 'react';
import DownBoldOutlined from '@universe-design/icons-react/DownBoldOutlined';
import { useLocale } from '../config-provider';
import { HorizontalMenuInk } from './HorizontalMenuInk';
import { MenuContext } from './MenuContext';

export const MenuMoreContent = () => {
  const locale = useLocale();
  return <span>{locale.global.more}</span>;
};

const MenuMore = () => {
  const context = React.useContext(MenuContext);
  const { prefixCls } = context;

  return (
    <>
      <MenuMoreContent />
      <DownBoldOutlined className={`${prefixCls}-overflow-expandIcon`} />
      <HorizontalMenuInk />
    </>
  );
};

export default MenuMore;
